INSERT OR IGNORE INTO rods (equipmentName, equipmentType, category, subCategory, model, description, strengthKg, form, testG, sensitivity, hardness, levelReq, structure, ability, rating, weightG, adaptWeight, adaptWeightG, goldPrice, silverPrice, lengthM) VALUES ('Corona CST', '鱼竿', '枪柄竿', 'Corona CST', 'Corona CST C60MH', 'Corona CST - 来自Express Fishing公司的著名系列Corona的枪柄竿版本。 除了是经典的Corona绞钓竿，这也是一个通用的入门级钓竿。如有缩写CST，此系列是供倍增鱼线轮用的。Corona CST系列竿胚由高模量碳纤维制成，配备现代化的导环Tunlao – RCS С。这个系列的相对较小长度的绞竿使它们可以舒适的用于在有藻类丛生的中小型水塘岸边捕捉中小型掠食性鱼类。绞钓初学者的选择。', '4.2kg', '枪柄竿', 0, 3/10, '7/10', '0', '超快的', '中等重的', '', '', '', 10-30g, '', '30', '1.8m');

COMMIT;
